form:Form.form:Scripts:
		function sendReqAsync(content, callBack) {
    var msg;
    var objDoc;

    if (content == null)
        content = "";

    msg = "<http-envelope service='ProxyEngine' request='send' user-token='" + g_strToken + "'>" + content + "</http-envelope>";

    var hr = getHR();                 
    hr.open("POST", g_location + "ProxyEngine.aspx", true);
    hr.onreadystatechange = function() 
    { 
      //Resultado
      if (hr.readyState == 4) 
      {
        if (hr.status == 200) 
        {
            try 
            {
              objDoc = createDoc(hr.responseText);
            } catch (e) 
            {
              alert("sendReqAsync(): " + e.number + "  " + e.description);
					  enable_buttons();
				    return;
            }

            //Envia el resultado
            if (callBack)
              callBack(objDoc);
        } else 
        {
          alert("sendReqAsync(): ERROR " + hr.status);
			  enable_buttons();
		    return;
        }
      }
    };

    hr.send(msg);
}


function SQLGetAsync(qry, param, callBack) 
{                              
sendReqAsync("<content-send SrvName=\"xquery\" Request=\"get-sql\" ><qry:declare xmlns:qry=\"nomad_engine.form\">"+param+"</qry:declare>"+qry+"</content-send>", function(doc) { 

    //Switchea las posibles respuestas
    strService  = doc.documentElement.attributes.getNamedItem("service").value;
    strResponse = doc.documentElement.attributes.getNamedItem("response").value;

    switch (strResponse) 
    {
        case "send-response":
          var eleResponse = doc.documentElement.childNodes.item(0);
          objResult = new NomadProxyResponse(eleResponse.attributes.getNamedItem("service").value, eleResponse.attributes.getNamedItem("response").value, eleResponse.childNodes.item(0));

				//Resultado                                       
          //Envia el resultado
          if (callBack)
            callBack(objResult.Message());
		    return;

        default:
          alert("invalid server reply, "+strResponse);
			  enable_buttons();
		    return;
    }
});
}

var arrLIQUIDACIONES = [];
var formEnabled = true;
var pointCount;


function PREV_exec_qry()
{
  return null;
}


function POST_exec_qry(resultArray)
{
  return;
}

function exec_qry_async(callBackFunction)
{
  var np, i;
  var start = new Date();

  np = GetProxy();
  var qry = Ctrl("main").getResource("LIQ_qry_" + Ctrl("tab_liquidacion_filtro").GetSelectedPanelID());	
  var qryMembers = qry.split("##");
  var qryMembers = qryMembers[1].split(",");
  var qryExt = null;

  var MyMSG = PREV_exec_qry();
  if (MyMSG)
  {
    alert(MyMSG);
  enable_buttons();
    return;
  }

//Validaciones Basicas
  var nmdDATA=new NomadXML("PARAM");
  for (i=0; i<qryMembers.length; i++)
  {     
    if(Ctrl(qryMembers[i]))
    {
      if (Ctrl(qryMembers[i]).m_Required && Ctrl(qryMembers[i]).GetXValue()=="")
      {
        alert("El valor es requerido");
		  enable_buttons();        
		  Ctrl(qryMembers[i]).SetFocus();
	    return;
      }
      nmdDATA.SetAttr(qryMembers[i], Ctrl(qryMembers[i]).GetXValue());
    }
  }                  

//Consulta principal
SQLGetAsync(
	qry, 
	nmdDATA.ToString(), 
	function(result) 
	{ 
	  var resultArray = STR2array(result);

  	POST_exec_qry(resultArray);
  	if (callBackFunction)
  		callBackFunction(resultArray);
	} 
);
}



//Transaforma un XML(tipo STRING) en ARRAY
function STR2array(str)
{
  var arr = new Array();

  var cur = 0, pos;
  while(true) 
  {
    pos = str.indexOf("id=\"", cur);
    if (pos < 0) break;

    cur = pos+4;
    pos = str.indexOf("\"", cur);
    arr.push(str.substr(cur, pos-cur));
    cur = pos+1;
  }

  return arr;
}


function ONLOAD_CUSTOM()
{
//Valores Iniciales
if (Ctrl("liqs").GetXValue())
	arrLIQUIDACIONES = Ctrl("liqs").GetXValue().split(',');

 	//Actualizo la Lista
refreshLiquidacion();       
}       

function clear_CUSTOM()
{                                        
arrLIQUIDACIONES = [];
  Ctrl("LIQ_listFILTER").SetXValue("");
  Ctrl("LIQ_arrcheckFILTER").DelAllRow();
  refreshLiquidacion();
}


function refreshLiquidacion(msg)
{              
 	var page=Ctrl("LIQ_listFILTER").Page;
Ctrl("LIQ_listFILTER").IDs=arrLIQUIDACIONES;
Ctrl("LIQ_listFILTER").ResetSQL();
Ctrl("LIQ_listFILTER").GotoPage(page);

enable_buttons(msg);
}

//Agrega al Array A los elementos del Array B
function union(arrayA, arrayB)
{
  var t;
  var tmp=new Array();

  //Creo la HASH
  for (t=0; t<arrayA.length; t++) 
  tmp["K"+arrayA[t]]=1;

  //Agrego los que no estan
  for (t=0; t<arrayB.length; t++) 
    if (tmp["K"+arrayB[t]]?false:true)
      arrayA.push(arrayB[t]);
}


//Elimina del Array A los elementos del Array B
function remove(arrayA, arrayB)
{
  var t;
  var tmp1=new Array();
  var tmp2=new Array();

  //Creo la HASH
  for (t=0; t<arrayB.length; t++) 
    tmp1["K"+arrayB[t]]=1;
  for (t=0; t<arrayA.length; t++) 
    tmp2.push(arrayA[t]);

  //Limpio el array
  arrayA.length=0;

  //Agrego los elemento NO comunes
  for (t=0; t<tmp2.length; t++)      
    if (tmp1["K"+tmp2[t]]?false:true)
      arrayA.push(tmp2[t]);
} 

//Elimina del Array A los elementos que no estan en el Array B
function intersect(arrayA, arrayB)
{
  var t;
  var tmp1=new Array();
  var tmp2=new Array();   

  //Creo la HASH
  for (t=0; t<arrayB.length; t++) 
    tmp1["K"+arrayB[t]]=1;
  for (t=0; t<arrayA.length; t++) 
    tmp2.push(arrayA[t]);

  //Limpio el array
  arrayA.length=0;

  //Agrego los elemento NO comunes
  for (t=0; t<tmp2.length; t++)      
  if (tmp1["K"+tmp2[t]]?true:false)
    arrayA.push(tmp2[t]);
}

//Elimina del Array A los elementos que no estan en el Array B
function copiar(arrayA, arrayB)
{
  //Limpio el array
  arrayA.length=0;

  //Agrego los elemento NO comunes
  for (var t=0; t<arrayB.length; t++)      
    arrayA.push(arrayB[t]);
}


function liq_load()    
{       
//Mensaje
disable_buttons("Cargando liquidaciones a la lista...");

//Optener el resultado
  exec_qry_async(
  function(auxArr) 
  { 
	  if (auxArr==null) return;

	  arrLIQUIDACIONES = auxArr; 
	  refreshLiquidacion();
  }
  );
}

function liq_loadadd() 
{ 
//Mensaje
disable_buttons("Agregando liquidaciones a la lista...");

//Optener el resultado
  exec_qry_async(
  function(auxArr) 
  { 
	  if (auxArr==null) return;  

   	//Quito los repetidos
	  remove(auxArr, arrLIQUIDACIONES);

	  union(arrLIQUIDACIONES, auxArr);	
	  refreshLiquidacion(auxArr.length ? " (" + auxArr.length+ " registros agregados)" : " (no se agregaron registros)");
  }
  );
}

function liq_filter()  
{ 
//Mensaje
disable_buttons("Filtrando liquidaciones de la lista...");

//Optener el resultado
  exec_qry_async(
  function(auxArr) 
  { 
	  if (auxArr==null) return;  

	  intersect(arrLIQUIDACIONES, auxArr);	
	  refreshLiquidacion();
  }
  );
}





//Elimino iten del FILTRO
function delLIQ()
{
var cnt = 0;
  for (var X=0; X<arrLIQUIDACIONES.length; X++)
  {
    if (Ctrl("LIQ_arrcheckFILTER").GetRowByAttr("ID",arrLIQUIDACIONES[X])!=null)
    {                        
      arrLIQUIDACIONES.splice(X,1);
      X--; cnt++;
    }
  }

  Ctrl("LIQ_listFILTER").SetXValue("");
 	Ctrl("LIQ_arrcheckFILTER").DelAllRow();
  refreshLiquidacion(cnt ? " (se quitaron " + cnt+ " registros)" : " (no se quitaron registros)");
}


//Limpio la Lista del FILTRO
function clearLIQ()
{  
var cnt = 0;
  for (var X=0; X<arrLIQUIDACIONES.length; X++)
  {
    if (Ctrl("LIQ_arrcheckFILTER").GetRowByAttr("ID",arrLIQUIDACIONES[X])==null)
    {                        
      arrLIQUIDACIONES.splice(X,1);
      X--; cnt++;
    }
  }

  Ctrl("LIQ_listFILTER").SetXValue("");
  Ctrl("LIQ_arrcheckFILTER").DelAllRow();
  refreshLiquidacion(cnt ? " (se quitaron " + cnt+ " registros)" : " (no se quitaron registros)");
}


function checkLIQ()
{                   
if (formEnabled)
{
	var X=Ctrl("LIQ_listFILTER").GetXValue();

  if (X!="" && Ctrl("LIQ_listFILTER").LastColumnClick!="SEL")
  {                              
    if (Ctrl("LIQ_arrcheckFILTER").GetRowByAttr("ID",X)==null) 
    {
      Ctrl("LIQ_arrcheckFILTER").AddRow().SetAttr("ID",X);
    }
    else 
    {   
      Ctrl("LIQ_arrcheckFILTER").DelRowByAttr("ID",X);    
    }
    Ctrl("LIQ_listFILTER").SetXValue("");
    refreshLiquidacion();
  } 
  else                     
  {
    enable_buttons();
  }
  }
}

//Deschequeo TOTAL
function unmarkLIQ()
{                 
var cnt = Ctrl("LIQ_arrcheckFILTER").CountRow();
  Ctrl("LIQ_listFILTER").SetXValue("");
  Ctrl("LIQ_arrcheckFILTER").DelAllRow();
  refreshLiquidacion(cnt ? " (se quitaron " + cnt+ " marcas)" : " (no se quitaron marcas)");
}



//Function para activar y desactivar Botones
function enable_buttons(msg)
{ 
if (Ctrl("LIQ_listFILTER").SetMessage) Ctrl("LIQ_listFILTER").SetMessage(null);
  CtrlEnabled("LIQ_listFILTER_Delete", Ctrl("LIQ_arrcheckFILTER").CountRow()==0?false:true);
  CtrlEnabled("LIQ_listFILTER_Clear" , true);

  CtrlEnabled("vgroupDatosLiqs", true);                             
  CtrlEnabled("vgroupDatosCustom", true);        

  enable_custom_buttons();
  loadingMessage(false, null);
  formEnabled = true;

  Ctrl("liq_filtrados").SetXValue("Liquidaciones Filtradas: "+arrLIQUIDACIONES.length+(msg?msg:""));
}

function enable_custom_buttons()
{                       
}


//Function para activar y desactivar Botones
function disable_buttons(msg)
{                           
loadingMessage(true, msg);
Ctrl("liq_filtrados").SetXValue(msg);
if (Ctrl("LIQ_listFILTER").SetMessage) Ctrl("LIQ_listFILTER").SetMessage(msg);

  CtrlEnabled("vgroupDatosLiqs", false);
  CtrlEnabled("vgroupDatosCustom", false);        


  disable_custom_buttons();
  formEnabled = false;     
  pointCount = 0;
pointAdd();  
}      

function disable_custom_buttons()
{
}

function pointAdd()
{
if (formEnabled) return;

var msg = Ctrl("liq_filtrados").GetXValue();
msg += "."; pointCount++;               
if (pointCount > 5) { msg = msg.substr(0,msg.length-pointCount); pointCount=0; }
Ctrl("liq_filtrados").SetXValue(msg);


setTimeout(pointAdd, 200);
}



function ACCEPT()
{               
//Controlo la cantidad de liquidaciones
 	if (arrLIQUIDACIONES.length==0)
 		return "No hay liquidaciones selecionadas.";
 	if (arrLIQUIDACIONES.length>100)
 		return "Demasiadas Liquidaciones.";
Ctrl("liqs").SetXValue(arrLIQUIDACIONES.join(","));


//Valido el largo del QUERY, es muy importante.
var WHERE = Ctrl("where").GetXValue();
if (WHERE.length > 2000)
	return "El resultado es muy grande y no podra ser procesado por el motor de Base de datos.";

}

